output.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT(ABS((?maxColl - ?minColl) -(?maxRich - ?minRich)) AS ?difference) WHERE {
  {
    SELECT(MIN(YEAR(?dateColl)) AS ?minColl)(MAX(YEAR(?dateColl)) AS ?maxColl) WHERE {
      ?seasonColl wdt:P1346 wd:Q249679 .
      ?seasonColl wdt:P585 ?dateColl .
    }
  }
  {
    SELECT(MIN(YEAR(?dateRich)) AS ?minRich)(MAX(YEAR(?dateRich)) AS ?maxRich) WHERE {
      ?seasonRich wdt:P1346 wd:Q2521385 .
      ?seasonRich wdt:P585 ?dateRich .
    }
  }
}

